function initThree() {
    const canvas = document.getElementById('webgl-canvas');
    
    // 1. Scene & Background
    scene = new THREE.Scene();
    
    // 2. Camera
    camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.position.copy(currentCameraPos);
    
    // 3. Renderer
    renderer = new THREE.WebGLRenderer({ canvas: canvas, antialias: true, alpha: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    
    // 4. Ánh sáng
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.4);
    scene.add(ambientLight);
    
    const pinkLight = new THREE.PointLight(0xff6b8b, 2.5, 100);
    pinkLight.position.set(20, 20, 20);
    scene.add(pinkLight);
    
    const purpleLight = new THREE.PointLight(0x8611e2, 2.5, 100);
    purpleLight.position.set(-20, -20, 20);
    scene.add(purpleLight);

    // 5. Tạo bầu trời sao (Starfield)
    createStarfield();
    
    // 6. Tạo hành tinh trung tâm (Sao Thổ)
    createPlanet();
    
    // 7. Tạo hệ thống hạt trái tim và các trạng thái vị trí
    createHeartParticles();
    
    // 8. Tạo nhóm vật thể bay cho Cảnh 2
    floatingGroup = new THREE.Group();
    scene.add(floatingGroup);
    
    // 9. Tạo nhóm pháo hoa cho Cảnh 5
    fireworkGroup = new THREE.Group();
    scene.add(fireworkGroup);

    // Lắng nghe sự kiện đổi kích thước màn hình
    window.addEventListener('resize', onWindowResize);
}

