// Tạo vân hành tinh dạng sọc bằng Canvas
function createPlanetTexture() {
    const canvas = document.createElement('canvas');
    canvas.width = 512;
    canvas.height = 512;
    const ctx = canvas.getContext('2d');
    
    const grad = ctx.createLinearGradient(0, 0, 0, 512);
    grad.addColorStop(0, '#ff758c');
    grad.addColorStop(0.3, '#ff7eb3');
    grad.addColorStop(0.6, '#b155ff');
    grad.addColorStop(1, '#6c11e2');
    
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 512, 512);
    
    // Vẽ các sọc nhạt xung quanh hành tinh tạo hiệu ứng Sao Thổ
    ctx.fillStyle = 'rgba(255, 255, 255, 0.08)';
    for (let i = 0; i < 25; i++) {
        const y = Math.random() * 512;
        const h = 4 + Math.random() * 20;
        ctx.fillRect(0, y, 512, h);
    }
    return new THREE.CanvasTexture(canvas);
}

// Tạo hành tinh và đai dẹt
function createPlanet() {
    // Khối cầu hành tinh
    const planetGeo = new THREE.SphereGeometry(12, 64, 64);
    const planetMat = new THREE.MeshStandardMaterial({
        map: createPlanetTexture(),
        roughness: 0.6,
        metalness: 0.1,
        bumpScale: 0.05
    });
    planet = new THREE.Mesh(planetGeo, planetMat);
    scene.add(planet);
    
    // Vòng đai bụi mỏng phát sáng (Saturn Ring)
    const ringGeo = new THREE.RingGeometry(14, 25, 64);
    // Xoay vòng đai nằm ngang
    ringGeo.rotateX(Math.PI / 2);
    
    const ringMat = new THREE.MeshBasicMaterial({
        color: 0xffffff,
        side: THREE.DoubleSide,
        transparent: true,
        opacity: 0.25,
        depthWrite: false
    });
    planetRing = new THREE.Mesh(ringGeo, ringMat);
    scene.add(planetRing);

    // Chữ chạy quanh hành tinh dạng hình trụ trong suốt
    const textTexture = createTextTexture(CONFIG.orbitingText);
    const textGeo = new THREE.CylinderGeometry(23.5, 23.5, 2, 64, 1, true);
    const textMat = new THREE.MeshBasicMaterial({
        map: textTexture,
        transparent: true,
        side: THREE.DoubleSide,
        depthWrite: false,
        blending: THREE.AdditiveBlending
    });
    textCylinder = new THREE.Mesh(textGeo, textMat);
    // Nghiêng nhẹ chữ cùng chiều vòng đai
    textCylinder.rotation.x = 0.1;
    scene.add(textCylinder);
}

// Vẽ chữ lên Texture Cylinder
function createTextTexture(text) {
    const canvas = document.createElement('canvas');
    canvas.width = 2048;
    canvas.height = 128;
    const ctx = canvas.getContext('2d');
    
    ctx.clearRect(0, 0, 2048, 128);
    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
    ctx.font = 'bold 50px "Dancing Script", cursive';
    ctx.shadowColor = '#ff6b8b';
    ctx.shadowBlur = 15;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    
    // Vẽ chữ lặp lại để tạo vòng tròn liền mạch
    ctx.fillText(text, 1024, 64);
    
    const texture = new THREE.CanvasTexture(canvas);
    texture.wrapS = THREE.RepeatWrapping;
    texture.wrapT = THREE.RepeatWrapping;
    return texture;
}

// Bầu trời sao lấp lánh nền
function createStarfield() {
    const starGeo = new THREE.BufferGeometry();
    const starPositions = new Float32Array(2000 * 3);
    
    for (let i = 0; i < 2000 * 3; i += 3) {
        // Phân bổ sao ngẫu nhiên trong khối cầu bán kính lớn
        const radius = 300 + Math.random() * 300;
        const u = Math.random();
        const v = Math.random();
        const theta = u * 2.0 * Math.PI;
        const phi = Math.acos(2.0 * v - 1.0);
        
        starPositions[i] = radius * Math.sin(phi) * Math.cos(theta);
        starPositions[i+1] = radius * Math.sin(phi) * Math.sin(theta);
        starPositions[i+2] = radius * Math.cos(phi);
    }
    
    starGeo.setAttribute('position', new THREE.BufferAttribute(starPositions, 3));
    
    // Tạo hạt hình tròn nhỏ làm sao
    const canvas = document.createElement('canvas');
    canvas.width = 16;
    canvas.height = 16;
    const ctx = canvas.getContext('2d');
    const grad = ctx.createRadialGradient(8, 8, 0, 8, 8, 8);
    grad.addColorStop(0, 'rgba(255, 255, 255, 1)');
    grad.addColorStop(1, 'rgba(255, 255, 255, 0)');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 16, 16);
    
    const starTexture = new THREE.CanvasTexture(canvas);
    const starMat = new THREE.PointsMaterial({
        size: 2,
        map: starTexture,
        transparent: true,
        blending: THREE.AdditiveBlending,
        depthWrite: false
    });
    
    starField = new THREE.Points(starGeo, starMat);
    scene.add(starField);
}

// Tạo hạt trái tim
function createHeartTexture() {
    const canvas = document.createElement('canvas');
    canvas.width = 64;
    canvas.height = 64;
    const ctx = canvas.getContext('2d');
    
    // Vẽ hình trái tim vector mềm mại phát sáng
    ctx.beginPath();
    ctx.moveTo(32, 16);
    ctx.bezierCurveTo(32, 16, 28, 4, 16, 4);
    ctx.bezierCurveTo(4, 4, 4, 24, 4, 24);
    ctx.bezierCurveTo(4, 36, 18, 48, 32, 60);
    ctx.bezierCurveTo(46, 48, 60, 36, 60, 24);
    ctx.bezierCurveTo(60, 24, 60, 4, 48, 4);
    ctx.bezierCurveTo(36, 4, 32, 16, 32, 16);
    ctx.closePath();
    
    // Tô màu đỏ hồng gradient phát sáng viền
    const grad = ctx.createRadialGradient(32, 32, 5, 32, 32, 28);
    grad.addColorStop(0, '#ffffff');
    grad.addColorStop(0.2, '#ff85a2');
    grad.addColorStop(0.8, '#ff3b64');
    grad.addColorStop(1, 'rgba(255,59,100,0)');
    
    ctx.fillStyle = grad;
    ctx.fill();
    
    return new THREE.CanvasTexture(canvas);
}

// Tạo hạt trái tim và các tư thế tọa độ của nó
function createHeartParticles() {
    const heartGeo = new THREE.BufferGeometry();
    const currentPositions = new Float32Array(particleCount * 3);
    
    // Khởi tạo các mảng tọa độ
    positionsRing = new Float32Array(particleCount * 3);
    positionsDense = new Float32Array(particleCount * 3);
    positionsGalaxy = new Float32Array(particleCount * 3);
    positionsHeartShape = new Float32Array(particleCount * 3);
    
    for (let i = 0; i < particleCount; i++) {
        const i3 = i * 3;
        
        // --- 1. Tạo vị trí Vòng đai mặc định (Scene 1 & 2) ---
        const r1 = 15 + Math.random() * 15;
        const theta1 = Math.random() * Math.PI * 2;
        positionsRing[i3] = Math.cos(theta1) * r1;
        positionsRing[i3+1] = (Math.random() - 0.5) * 1.5;
        positionsRing[i3+2] = Math.sin(theta1) * r1;
        
        // --- 2. Tạo vị trí Vòng đai dày hội tụ (Scene 3) ---
        const r2 = 21 + Math.random() * 2.5; // Tập trung sát mép ngoài hành tinh
        const theta2 = Math.random() * Math.PI * 2;
        positionsDense[i3] = Math.cos(theta2) * r2;
        positionsDense[i3+1] = (Math.random() - 0.5) * 0.4; // Cực kỳ mỏng dẹt
        positionsDense[i3+2] = Math.sin(theta2) * r2;
        
        // --- 3. Tạo vị trí Dải ngân hà xoắn ốc (Scene 4) ---
        const arms = 3;
        const armIndex = i % arms;
        const t = Math.random();
        const r3 = 13 + t * 45;
        const theta3 = armIndex * ((Math.PI * 2) / arms) + t * 4.5;
        positionsGalaxy[i3] = Math.cos(theta3) * r3;
        positionsGalaxy[i3+1] = (Math.random() - 0.5) * (6 - t * 4);
        positionsGalaxy[i3+2] = Math.sin(theta3) * r3;
        
        // --- 4. Tạo vị trí Hình Trái Tim Khổng Lồ (Scene 5) ---
        // Sử dụng công thức trái tim 3D toán học nổi tiếng
        const u = Math.random() * Math.PI * 2;
        const v = Math.random() * Math.PI - Math.PI/2;
        
        // Công thức trái tim 3D
        const x = 16 * Math.pow(Math.sin(u), 3);
        const y = 13 * Math.cos(u) - 5 * Math.cos(2*u) - 2 * Math.cos(3*u) - Math.cos(4*u);
        const z = (Math.random() - 0.5) * 8;
        
        // Điều chỉnh tỉ lệ kích thước hình trái tim
        const scale = 1.3;
        positionsHeartShape[i3] = x * scale;
        // Dịch lên trên một chút để khớp với trung tâm ảnh Nick & Judy
        positionsHeartShape[i3+1] = (y * scale) + 5; 
        positionsHeartShape[i3+2] = z * scale;
        
        // Mặc định vị trí hiện tại sẽ copy từ Vòng đai 1
        currentPositions[i3] = positionsRing[i3];
        currentPositions[i3+1] = positionsRing[i3+1];
        currentPositions[i3+2] = positionsRing[i3+2];
    }
    
    heartGeo.setAttribute('position', new THREE.BufferAttribute(currentPositions, 3));
    
    // Material hạt sáng rực rỡ
    const heartMat = new THREE.PointsMaterial({
        size: 1.2,
        map: createHeartTexture(),
        transparent: true,
        blending: THREE.AdditiveBlending,
        depthWrite: false,
        sizeAttenuation: true
    });
    
    heartParticles = new THREE.Points(heartGeo, heartMat);
    scene.add(heartParticles);
}

