// Hàm phụ vẽ hình trái tim lên canvas
function drawHeartPath(ctx, x, y, width, height) {
    ctx.beginPath();
    ctx.moveTo(x + width/2, y + height*0.25);
    ctx.bezierCurveTo(x + width/2, y + height*0.25, x + width*0.43, y, x + width*0.25, y);
    ctx.bezierCurveTo(x, y, x, y + height*0.375, x, y + height*0.375);
    ctx.bezierCurveTo(x, y + height*0.56, x + width*0.28, y + height*0.75, x + width/2, y + height);
    ctx.bezierCurveTo(x + width*0.72, y + height*0.75, x + width, y + height*0.56, x + width, y + height*0.375);
    ctx.bezierCurveTo(x, y + height*0.375, x, y, x + width*0.75, y);
    ctx.bezierCurveTo(x + width*0.57, y, x + width/2, y + height*0.25, x + width/2, y + height*0.25);
    ctx.closePath();
}

// Vẽ hai trái tim lồng vào nhau (thay thế cho Castle)
function createCastleCanvas() {
    const canvas = document.createElement('canvas');
    canvas.width = 256;
    canvas.height = 256;
    const ctx = canvas.getContext('2d');
    
    ctx.clearRect(0, 0, 256, 256);
    
    // Trái tim 1: Hồng nhạt (Phía sau)
    ctx.fillStyle = '#ff85a2';
    drawHeartPath(ctx, 40, 80, 110, 110);
    ctx.fill();
    ctx.strokeStyle = '#ffffff';
    ctx.lineWidth = 4;
    ctx.stroke();
    
    // Trái tim 2: Đỏ hồng rực rỡ (Phía trước)
    ctx.fillStyle = '#ff4d6d';
    drawHeartPath(ctx, 100, 50, 110, 110);
    ctx.fill();
    ctx.strokeStyle = '#ffffff';
    ctx.lineWidth = 4;
    ctx.stroke();
    
    // Vẽ các chấm sáng nhỏ (lấp lánh) xung quanh
    const sparkles = [
        {x: 30, y: 60, r: 4}, {x: 220, y: 70, r: 3}, {x: 80, y: 210, r: 4},
        {x: 210, y: 180, r: 5}, {x: 130, y: 30, r: 3}, {x: 180, y: 220, r: 3}
    ];
    ctx.fillStyle = '#ffe066';
    sparkles.forEach(s => {
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
        ctx.fill();
    });
    
    return canvas;
}

// Vẽ trái tim có mũi tên thần tình yêu xuyên qua (thay thế cho Up House)
function createUpHouseCanvas() {
    const canvas = document.createElement('canvas');
    canvas.width = 256;
    canvas.height = 256;
    const ctx = canvas.getContext('2d');
    
    ctx.clearRect(0, 0, 256, 256);
    
    // 1. Vẽ trái tim trung tâm
    ctx.fillStyle = '#ff3b64';
    drawHeartPath(ctx, 68, 68, 120, 120);
    ctx.fill();
    ctx.strokeStyle = '#ffffff';
    ctx.lineWidth = 5;
    ctx.stroke();
    
    // 2. Vẽ mũi tên xuyên qua
    // Thân mũi tên (vàng)
    ctx.strokeStyle = '#ffe066';
    ctx.lineWidth = 6;
    ctx.beginPath();
    ctx.moveTo(35, 35);
    ctx.lineTo(221, 221);
    ctx.stroke();
    
    // Đầu mũi tên (Hình tam giác hướng xuống dưới phải)
    ctx.fillStyle = '#ffd633';
    ctx.beginPath();
    ctx.moveTo(221, 221);
    ctx.lineTo(215, 195);
    ctx.lineTo(195, 215);
    ctx.closePath();
    ctx.fill();
    
    // Đuôi mũi tên (Lông vũ)
    ctx.strokeStyle = '#ffe066';
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.moveTo(35, 35); ctx.lineTo(20, 25);
    ctx.moveTo(40, 40); ctx.lineTo(25, 30);
    ctx.moveTo(45, 45); ctx.lineTo(30, 35);
    
    ctx.moveTo(35, 35); ctx.lineTo(25, 20);
    ctx.moveTo(40, 40); ctx.lineTo(30, 25);
    ctx.moveTo(45, 45); ctx.lineTo(35, 30);
    ctx.stroke();
    
    // Lấp lánh xung quanh
    const sparkles = [
        {x: 60, y: 50, r: 3}, {x: 200, y: 60, r: 4}, {x: 50, y: 190, r: 5},
        {x: 180, y: 210, r: 3}, {x: 130, y: 40, r: 4}
    ];
    ctx.fillStyle = '#ffe066';
    sparkles.forEach(s => {
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
        ctx.fill();
    });
    
    return canvas;
}

// Hàm tải ảnh từ URL vẽ lên khung hình trái tim để tạo Mesh
function createPhotoHeartMesh(url, index, callback) {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = function() {
        const canvas = document.createElement('canvas');
        canvas.width = 256;
        canvas.height = 256;
        const ctx = canvas.getContext('2d');
        
        // Vẽ khung clip hình trái tim
        ctx.beginPath();
        ctx.moveTo(128, 64);
        ctx.bezierCurveTo(128, 64, 112, 16, 64, 16);
        ctx.bezierCurveTo(16, 16, 16, 96, 16, 96);
        ctx.bezierCurveTo(16, 144, 72, 192, 128, 240);
        ctx.bezierCurveTo(184, 192, 240, 144, 240, 96);
        ctx.bezierCurveTo(240, 96, 240, 16, 192, 16);
        ctx.bezierCurveTo(144, 16, 128, 64, 128, 64);
        ctx.closePath();
        ctx.clip();
        
        // Vẽ đè bức ảnh của bạn lên
        ctx.drawImage(img, 0, 0, 256, 256);
        
        // Thêm viền trắng lãng mạn cho trái tim ảnh
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 10;
        ctx.stroke();
        
        const texture = new THREE.CanvasTexture(canvas);
        const geo = new THREE.PlaneGeometry(8, 8);
        const mat = new THREE.MeshBasicMaterial({
            map: texture,
            transparent: true,
            side: THREE.DoubleSide
        });
        
        const mesh = new THREE.Mesh(geo, mat);
        // Lưu lại dữ liệu ảnh gốc để xem phóng to khi click
        mesh.userData = { isPhoto: true, url: url, index: index };
        callback(mesh);
    };
    img.src = url;
}

