function loadScene2FloatingObjects() {
    if (isFloatingLoaded) return;
    isFloatingLoaded = true;
    
    // Tạo 6 khung ảnh trái tim chứa hình cặp đôi (thay thế lâu đài và ngôi nhà bóng bay, thêm ảnh thứ 6 cho cân đối)
    const photoPositions = [
        new THREE.Vector3(-14, 5, 15),   // Ảnh 1 (Áo xanh rêu - Bên trái)
        new THREE.Vector3(12, -5, 18),   // Ảnh 2
        new THREE.Vector3(5, 12, -2),    // Ảnh 3
        new THREE.Vector3(22, 15, -15),  // Ảnh 4 (Vị trí lâu đài cũ)
        new THREE.Vector3(-25, 12, -10), // Ảnh 5 (Vị trí ngôi nhà Up cũ)
        new THREE.Vector3(14, 5, 15)     // Ảnh 6 (Ảnh ngày nhỏ - Đối xứng bên phải với Ảnh 1)
    ];
    
    CONFIG.photoUrls.forEach((url, index) => {
        createPhotoHeartMesh(url, index, (mesh) => {
            mesh.position.copy(photoPositions[index]);
            // Tạo góc nghiêng nhẹ
            mesh.rotation.set(
                (Math.random() - 0.5) * 0.3,
                (Math.random() - 0.5) * 0.3,
                (Math.random() - 0.5) * 0.2
            );
            floatingGroup.add(mesh);
        });
    });
    
    // Ban đầu ẩn toàn bộ nhóm vật thể bay, chỉ hiện khi vào Cảnh 2
    floatingGroup.visible = false;
}

/* =========================================================================
   CẢNH 5: HỆ THỐNG PHÁO HOA TRÁI TIM
   ========================================================================= */
class Firework {
    constructor(startX, startY, startZ) {
        this.position = new THREE.Vector3(startX, startY, startZ);
        this.color = new THREE.Color().setHSL(Math.random(), 1.0, 0.6);
        this.particles = [];
        this.maxAge = 80 + Math.floor(Math.random() * 40);
        this.age = 0;
        this.exploded = false;
        this.speedY = 0.5 + Math.random() * 0.4;
        
        // Mesh hạt bay lên ban đầu
        const canvas = document.createElement('canvas');
        canvas.width = 16;
        canvas.height = 16;
        const ctx = canvas.getContext('2d');
        const grad = ctx.createRadialGradient(8, 8, 0, 8, 8, 8);
        grad.addColorStop(0, '#ffffff');
        grad.addColorStop(1, 'rgba(255,255,255,0)');
        ctx.fillStyle = grad;
        ctx.fillRect(0,0,16,16);
        
        const tex = new THREE.CanvasTexture(canvas);
        const geo = new THREE.BufferGeometry();
        geo.setAttribute('position', new THREE.BufferAttribute(new Float32Array([this.position.x, this.position.y, this.position.z]), 3));
        const mat = new THREE.PointsMaterial({ size: 1.5, map: tex, transparent: true, blending: THREE.AdditiveBlending, depthWrite: false });
        
        this.spark = new THREE.Points(geo, mat);
        fireworkGroup.add(this.spark);
    }
    
    update() {
        if (!this.exploded) {
            // Bay lên cao dần
            this.position.y += this.speedY;
            this.position.x += Math.sin(this.position.y * 0.5) * 0.1;
            
            const positions = this.spark.geometry.attributes.position.array;
            positions[0] = this.position.x;
            positions[1] = this.position.y;
            positions[2] = this.position.z;
            this.spark.geometry.attributes.position.needsUpdate = true;
            
            // Đạt độ cao ngẫu nhiên thì nổ hình trái tim
            if (this.position.y >= 5 + Math.random() * 15) {
                this.explode();
            }
        } else {
            // Cập nhật các tia nổ
            this.age++;
            const positions = this.spark.geometry.attributes.position.array;
            
            for (let i = 0; i < this.particles.length; i++) {
                const p = this.particles[i];
                p.pos.add(p.vel);
                // Giảm tốc độ dần do ma sát không khí
                p.vel.multiplyScalar(0.96);
                
                const idx = i * 3;
                positions[idx] = p.pos.x;
                positions[idx+1] = p.pos.y;
                positions[idx+2] = p.pos.z;
            }
            this.spark.geometry.attributes.position.needsUpdate = true;
            
            // Độ mờ giảm dần theo độ tuổi pháo
            this.spark.material.opacity = 1.0 - (this.age / this.maxAge);
            
            if (this.age >= this.maxAge) {
                fireworkGroup.remove(this.spark);
                this.spark.geometry.dispose();
                this.spark.material.dispose();
                return false; // Pháo hoa đã biến mất hoàn toàn
            }
        }
        return true;
    }
    
    explode() {
        this.exploded = true;
        fireworkGroup.remove(this.spark);
        this.spark.geometry.dispose();
        
        const count = 180;
        const positions = new Float32Array(count * 3);
        
        // Tạo vận tốc bay theo hình dạng trái tim 3D ngọt ngào
        for (let i = 0; i < count; i++) {
            const angle = (i / count) * Math.PI * 2;
            
            // Công thức trái tim 2D/3D điều chỉnh vector hướng bắn
            const vx = 16 * Math.pow(Math.sin(angle), 3);
            const vy = 13 * Math.cos(angle) - 5 * Math.cos(2*angle) - 2 * Math.cos(3*angle) - Math.cos(4*angle);
            const vz = (Math.random() - 0.5) * 5;
            
            // Lực bắn ngẫu nhiên
            const force = 0.015 + Math.random() * 0.01;
            const velocity = new THREE.Vector3(vx * force, vy * force, vz * force);
            
            const partPos = this.position.clone();
            this.particles.push({ pos: partPos, vel: velocity });
            
            const idx = i * 3;
            positions[idx] = partPos.x;
            positions[idx+1] = partPos.y;
            positions[idx+2] = partPos.z;
        }
        
        const geo = new THREE.BufferGeometry();
        geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
        
        const tex = createHeartTexture();
        const mat = new THREE.PointsMaterial({
            size: 2.0,
            map: tex,
            transparent: true,
            blending: THREE.AdditiveBlending,
            depthWrite: false,
            color: this.color
        });
        
        this.spark = new THREE.Points(geo, mat);
        fireworkGroup.add(this.spark);
    }
}

/* =========================================================================
   VÒNG LẶP HOẠT ẢNH ANIMATION LOOP
   ========================================================================= */
function animate() {
    requestAnimationFrame(animate);
    
    // 1. Tự động quay Sao Thổ và các vòng đai
    if (planet) {
        planet.rotation.y += 0.003;
    }
    if (textCylinder) {
        textCylinder.rotation.y += 0.005; // Chữ chạy lướt
    }
    if (starField) {
        starField.rotation.y += 0.0003; // Sao lấp lánh nhẹ
    }
    
    // 2. Chuyển cảnh mượt mà cho hệ hạt trái tim (Lerp vị trí)
    if (heartParticles) {
        const positions = heartParticles.geometry.attributes.position.array;
        
        // Xác định mảng tọa độ mục tiêu dựa trên phân cảnh hiện tại
        let targetPosArray;
        if (currentSceneIndex === 0 || currentSceneIndex === 1) {
            targetPosArray = positionsRing;
        } else if (currentSceneIndex === 2) {
            targetPosArray = positionsDense;
        } else if (currentSceneIndex === 3) {
            targetPosArray = positionsGalaxy;
        } else { // Scene 5
            targetPosArray = positionsHeartShape;
        }
        
        // Tốc độ di chuyển hạt
        const lerpSpeed = 0.06; 
        
        for (let i = 0; i < particleCount * 3; i++) {
            positions[i] += (targetPosArray[i] - positions[i]) * lerpSpeed;
        }
        heartParticles.geometry.attributes.position.needsUpdate = true;
        
        // Tạo xoáy nhẹ cho quỹ đạo hạt ở các cảnh động
        if (currentSceneIndex !== 4) { // Ngoại trừ cảnh trái tim tĩnh
            const time = Date.now() * 0.0003;
            heartParticles.rotation.y = time;
        } else {
            heartParticles.rotation.y *= 0.95; // Dừng xoay nhanh chóng
        }
    }
    
    // 3. Hoạt ảnh bay bập bềnh của Lâu đài và Nhà UP (Cảnh 2)
    if (floatingGroup && floatingGroup.visible) {
        const time = Date.now() * 0.0015;
        // Bobbing nhẹ lên xuống
        floatingGroup.children.forEach((child, index) => {
            if (!child.userData.isPhoto) {
                child.position.y += Math.sin(time + index) * 0.015;
            } else {
                // Các khung ảnh xoay nhẹ
                child.rotation.y += 0.005;
                child.position.y += Math.cos(time + index) * 0.008;
            }
        });
    }
    
    // 4. Di chuyển Camera mượt mà (Lerp Camera Position & LookAt)
    const targetCam = cameraTargets[currentSceneIndex];
    currentCameraPos.lerp(targetCam.pos, 0.035);
    currentCameraLook.lerp(targetCam.lookAt, 0.035);
    
    camera.position.copy(currentCameraPos);
    camera.lookAt(currentCameraLook);
    
    // 5. Cập nhật hệ thống pháo hoa ở Cảnh 5
    if (currentSceneIndex === 4) {
        // Tự động bắn pháo hoa
        if (Math.random() < 0.05) {
            const startX = (Math.random() - 0.5) * 35;
            const startY = -20;
            const startZ = -15 + (Math.random() - 0.5) * 15;
            fireworks.push(new Firework(startX, startY, startZ));
        }
        
        // Cập nhật trạng thái từng quả pháo
        fireworks = fireworks.filter(fw => fw.update());
    }

    // 6. Xử lý ẩn hiện các thành phần tùy phân cảnh
    updateSceneVisibility();
    
    renderer.render(scene, camera);
}

// Xử lý bật/tắt các Mesh 3D tùy theo cảnh đang xem
function updateSceneVisibility() {
    if (!planet || !planetRing || !textCylinder) return;
    
    // Ở Cảnh 5, hành tinh và chữ mờ đi hoàn toàn
    if (currentSceneIndex === 4) {
        planet.material.transparent = true;
        planet.material.opacity = THREE.MathUtils.lerp(planet.material.opacity, 0.0, 0.05);
        
        planetRing.material.opacity = THREE.MathUtils.lerp(planetRing.material.opacity, 0.0, 0.05);
        textCylinder.material.opacity = THREE.MathUtils.lerp(textCylinder.material.opacity, 0.0, 0.05);
        
        // Ẩn nhóm vật thể bay Cảnh 2
        floatingGroup.visible = false;
    } else {
        planet.material.opacity = THREE.MathUtils.lerp(planet.material.opacity, 1.0, 0.05);
        planetRing.material.opacity = THREE.MathUtils.lerp(planetRing.material.opacity, 0.25, 0.05);
        textCylinder.material.opacity = THREE.MathUtils.lerp(textCylinder.material.opacity, 0.9, 0.05);
        
        // Hiển thị vật thể bay chỉ ở Cảnh 2
        if (currentSceneIndex === 1) {
            floatingGroup.visible = true;
            // Tải tài nguyên một lần duy nhất khi chạm cảnh 2
            loadScene2FloatingObjects();
        } else {
            floatingGroup.visible = false;
        }
    }
}

/* =========================================================================
   XỬ LÝ GIAO DIỆN NGƯỜI DÙNG (UI LOGIC)
   ========================================================================= */
function initUI() {
    const introScreen = document.getElementById('intro-screen');
    const giftBox = document.getElementById('gift-box');
    const musicToggle = document.getElementById('music-toggle');
    const bgMusic = document.getElementById('bg-music');
    const musicTooltip = document.querySelector('.music-tooltip');
    
    const btnNext = document.getElementById('btn-next');
    const btnPrev = document.getElementById('btn-prev');
    const dots = document.querySelectorAll('.dot');
    
    const confessionOverlay = document.getElementById('confession-overlay');
    const coupleImg = document.getElementById('couple-img');
    const btnYes = document.getElementById('btn-yes');
    const btnNo = document.getElementById('btn-no');
    const actionButtons = document.getElementById('action-buttons');
    const successMessage = document.getElementById('success-message');
    
    // Gán tài nguyên ảnh từ CONFIG vào giao diện
    coupleImg.src = CONFIG.coupleImgUrl;
    bgMusic.querySelector('source').src = CONFIG.musicUrl;
    bgMusic.load();

    // 1. Nhấp hộp quà mở đầu
    giftBox.addEventListener('click', () => {
        giftBox.classList.add('open');
        // Kích hoạt phát nhạc khi có tương tác người dùng đầu tiên
        bgMusic.play().then(() => {
            musicToggle.classList.add('playing');
            musicToggle.innerHTML = '<i class="fas fa-music"></i>';
            musicTooltip.classList.add('hidden');
        }).catch(err => console.log("Tự động phát nhạc bị trình duyệt chặn:", err));
        
        // Fade out Intro Screen sau khi mở hộp quà
        setTimeout(() => {
            introScreen.style.opacity = '0';
            setTimeout(() => {
                introScreen.classList.add('hidden');
            }, 1000);
        }, 1200);
    });

    // 2. Trình phát nhạc
    musicToggle.addEventListener('click', () => {
        if (bgMusic.paused) {
            bgMusic.play();
            musicToggle.classList.add('playing');
            musicToggle.innerHTML = '<i class="fas fa-music"></i>';
        } else {
            bgMusic.pause();
            musicToggle.classList.remove('playing');
            musicToggle.innerHTML = '<i class="fas fa-volume-mute"></i>';
        }
    });

    // 3. Điều hướng phân cảnh (Next / Prev)
    btnNext.addEventListener('click', () => {
        if (currentSceneIndex < totalScenes - 1) {
            changeScene(currentSceneIndex + 1);
        }
    });

    btnPrev.addEventListener('click', () => {
        if (currentSceneIndex > 0) {
            changeScene(currentSceneIndex - 1);
        }
    });

    dots.forEach(dot => {
        dot.addEventListener('click', (e) => {
            const index = parseInt(e.target.dataset.scene);
            changeScene(index);
        });
    });

    // Hàm chuyển cảnh
    function changeScene(index) {
        currentSceneIndex = index;
        
        // Cập nhật trạng thái nút bấm
        btnPrev.disabled = currentSceneIndex === 0;
        
        if (currentSceneIndex === totalScenes - 1) {
            btnNext.innerHTML = 'Mở thư <i class="fas fa-heart"></i>';
            btnNext.style.background = '#ff4d6d';
            btnNext.style.color = 'white';
        } else {
            btnNext.innerHTML = 'Tiếp tục <i class="fas fa-chevron-right"></i>';
            btnNext.style.background = '';
            btnNext.style.color = '';
        }
        
        // Cập nhật dấu chấm tròn tiến trình
        dots.forEach(dot => dot.classList.remove('active'));
        dots[currentSceneIndex].classList.add('active');
        
        // Kích hoạt hộp thư tỏ tình ở Cảnh 5
        const scene5Bg = document.getElementById('scene5-bg');
        if (currentSceneIndex === 4) {
            confessionOverlay.classList.add('active');
            if (scene5Bg) scene5Bg.classList.add('active');
            // Hiển thị câu hỏi tỏ tình và căn giữa trước khi gõ thư
            const textElement = document.getElementById('typewriter-text');
            textElement.style.textAlign = 'center';
            textElement.innerHTML = "Quỳnh Châu ơi, cậu đồng ý làm người yêu tớ nhé? 💖";
            
            // Khôi phục nút Không về vị trí ban đầu trong card
            resetNoButton();
            
            // Hiển thị lại nút bấm và ẩn thông điệp thành công/bộ đếm nếu quay lại cảnh này
            actionButtons.classList.remove('hidden');
            successMessage.classList.add('hidden');
        } else {
            confessionOverlay.classList.remove('active');
            if (scene5Bg) scene5Bg.classList.remove('active');
            // Reset nếu quay lại
            document.getElementById('typewriter-text').innerHTML = "";
            successMessage.classList.add('hidden');
        }
    }

    // 4. Hiệu ứng gõ chữ của Lá thư
    let typewriterTimeout;
    function startTypewriter(onComplete) {
        const textElement = document.getElementById('typewriter-text');
        textElement.style.textAlign = 'left'; // Căn lề trái khi gõ bức thư chính thức
        textElement.innerHTML = "";
        clearTimeout(typewriterTimeout);
        
        let charIndex = 0;
        const text = CONFIG.confessionLetter;
        
        function type() {
            if (charIndex < text.length) {
                textElement.innerHTML += text.charAt(charIndex);
                charIndex++;
                // Cuộn xuống cuối lá thư tự động khi gõ chữ (chỉ cuộn nếu người dùng ở sát đáy để họ có thể tự kéo lên đọc lại nếu muốn)
                const wrapper = document.querySelector('.letter-content-wrapper');
                const isNearBottom = wrapper.scrollHeight - wrapper.scrollTop - wrapper.clientHeight < 40;
                if (isNearBottom) {
                    wrapper.scrollTop = wrapper.scrollHeight;
                }
                
                typewriterTimeout = setTimeout(type, 35);
            } else {
                if (typeof onComplete === 'function') {
                    onComplete();
                }
            }
        }
        type();
    }

    // Hàm phụ khôi phục nút Không về vị trí ban đầu trong card
    function resetNoButton() {
        btnNo.style.position = '';
        btnNo.style.left = '';
        btnNo.style.top = '';
        btnNo.style.zIndex = '';
        if (btnNo.parentElement !== actionButtons) {
            actionButtons.appendChild(btnNo);
        }
    }

    // 5. NÚT "KHÔNG" CHẠY TRỐN (Escape No Button)
    // Tự động nhảy đi vị trí ngẫu nhiên khi di chuột hoặc chạm vào màn hình điện thoại
    function escapeNoButton(e) {
        // Chiều rộng & cao của viewport màn hình
        const w = window.innerWidth;
        const h = window.innerHeight;
        
        // Tính toán tọa độ ngẫu nhiên mới đảm bảo không nhảy khỏi màn hình
        const buttonWidth = btnNo.offsetWidth;
        const buttonHeight = btnNo.offsetHeight;
        
        // Đưa nút bấm ra ngoài body để tránh bị ảnh hưởng bởi transform của card
        if (btnNo.parentElement !== document.body) {
            document.body.appendChild(btnNo);
        }
        
        // Đặt ở vị trí fixed ngẫu nhiên với biên an toàn 40px tránh góc màn hình bị khuất
        const randX = Math.random() * (w - buttonWidth - 80) + 40;
        const randY = Math.random() * (h - buttonHeight - 80) + 40;
        
        btnNo.style.position = 'fixed';
        btnNo.style.left = randX + 'px';
        btnNo.style.top = randY + 'px';
        btnNo.style.zIndex = '999';
    }

    // Lắng nghe cả di chuột (PC) và chạm tay (Điện thoại di động)
    btnNo.addEventListener('mouseover', escapeNoButton);
    btnNo.addEventListener('touchstart', (e) => {
        e.preventDefault(); // Tránh kích hoạt click
        escapeNoButton();
    });

    // Nhấp vào nút "Không" (nếu bằng cách nào đó nhấp trúng) -> Yêu cầu chọn lại
    btnNo.addEventListener('click', () => {
        alert("Không được từ chối tớ đâu nha! Cậu phải chọn Đồng ý đi mà 🥺💖");
        resetNoButton();
    });

    // 6. NÚT "ĐỒNG Ý" THÀNH CÔNG
    btnYes.addEventListener('click', () => {
        // Ẩn các nút bấm và khôi phục nút No về bình thường
        actionButtons.classList.add('hidden');
        resetNoButton();
        
        // Đổi biểu tượng trái tim thành hiệu ứng lung linh phóng to
        const glowHeart = document.querySelector('.glowing-heart-icon');
        if (glowHeart) glowHeart.style.transform = 'scale(1.5)';
        
        // Ẩn hộp thư tỏ tình để chạy màn hình loading và xe van trước
        confessionOverlay.classList.remove('active');
        
        // Kích hoạt màn hình loading
        runLoveLoader();
    });

    // Chạy màn hình Loading và hoạt ảnh Xe van chở tình yêu
    function runLoveLoader() {
        const loaderScreen = document.getElementById('love-loader-screen');
        const loaderBarFill = document.getElementById('loader-bar-fill');
        const loaderText = document.getElementById('loader-text');
        
        // Reset loader
        loaderBarFill.style.width = '0%';
        loaderText.innerText = '0%';
        loaderScreen.classList.remove('hidden');
        loaderScreen.style.opacity = '1';
        
        let percent = 0;
        const interval = setInterval(() => {
            percent += 1;
            loaderBarFill.style.width = percent + '%';
            loaderText.innerText = percent + '%';
            
            if (percent >= 100) {
                clearInterval(interval);
                loaderText.innerText = 'Ok rùi đó :)';
                
                // Đợi 1 giây rồi bắt đầu chạy xe van
                setTimeout(() => {
                    loaderScreen.style.opacity = '0';
                    setTimeout(() => {
                        loaderScreen.classList.add('hidden');
                        runVanDrive();
                    }, 500);
                }, 1000);
            }
        }, 30); // 100 * 30ms = 3 giây loading
    }

    function runVanDrive() {
        const driveScreen = document.getElementById('love-drive-screen');
        const vanContainer = document.getElementById('van-container');
        const dialogBubble = document.getElementById('dialog-bubble');
        const exhaustParticles = document.getElementById('exhaust-particles');
        
        // Reset xe van (Xuất phát xa hơn ở -400px do xe to gấp đôi)
        vanContainer.style.left = '-400px';
        dialogBubble.style.opacity = '0';
        exhaustParticles.innerHTML = '';
        
        driveScreen.classList.remove('hidden');
        driveScreen.style.opacity = '1';
        
        // Cho xe chạy vào
        setTimeout(() => {
            // Hiện bong bóng thoại trên xe van sau 1.5 giây (chạy chậm hơn nên hiện muộn hơn chút)
            setTimeout(() => {
                dialogBubble.style.opacity = '1';
            }, 1500);
            
            // Bắt đầu tạo khói xe hình trái tim (giảm nhịp độ xuống 180ms do xe chạy chậm)
            let exhaustInterval = setInterval(() => {
                createExhaustHeart();
            }, 180);
            
            // Chạy xe van từ trái sang phải chậm hơn (7 giây thay vì 3.5 giây)
            vanContainer.style.transition = 'left 7s cubic-bezier(0.25, 0.8, 0.25, 1)';
            vanContainer.style.left = '100vw'; // Xe chạy qua mép phải màn hình
            
            // Sau khi chạy xong xe van (đợi 7 giây)
            setTimeout(() => {
                clearInterval(exhaustInterval);
                driveScreen.style.opacity = '0';
                setTimeout(() => {
                    driveScreen.classList.add('hidden');
                    vanContainer.style.transition = ''; // reset transition
                    
                    // Hiển thị lại thiệp tỏ tình và bắt đầu gõ chữ bức thư tình như cũ
                    confessionOverlay.classList.add('active');
                    
                    startTypewriter(() => {
                        // Hiện thông điệp thành công
                        successMessage.classList.remove('hidden');
                    });
                }, 500);
            }, 7000); // 7s khớp với transition
        }, 100);
        
        // Hàm tạo hạt khói trái tim
        function createExhaustHeart() {
            const vanRect = vanContainer.getBoundingClientRect();
            // Ống xả của xe van to gấp đôi nằm ở khoảng cách +30px X và +140px Y
            const x = vanRect.left + 30;
            const y = vanRect.top + 140;
            
            // Chỉ tạo khói khi xe đang ở trên màn hình
            if (x < 0 || x > window.innerWidth) return;
            
            const heart = document.createElement('div');
            heart.className = 'exhaust-heart';
            
            const heartIcons = ['❤️', '💖', '💝', '💕', '💗', '💓'];
            heart.innerText = heartIcons[Math.floor(Math.random() * heartIcons.length)];
            
            heart.style.left = x + 'px';
            heart.style.top = y + 'px';
            
            // Random kích thước hạt nhẹ
            const size = 12 + Math.random() * 8;
            heart.style.fontSize = size + 'px';
            
            exhaustParticles.appendChild(heart);
            
            // Tự động xóa hạt khói sau 1.2s khi hoạt ảnh kết thúc
            setTimeout(() => {
                heart.remove();
            }, 1200);
        }
    }

    // Khởi động bong bóng trái tim bay trên màn hình mở đầu
    createIntroHearts();

    // Hàm phụ tạo các bong bóng trái tim bay trên màn hình mở đầu
    function createIntroHearts() {
        const heartsContainer = document.getElementById('intro-screen-hearts');
        if (!heartsContainer) return;
        
        const heartIcons = ['❤️', '💖', '💝', '💕', '💗', '💓'];
        
        // Tạo 25 hạt trái tim ngẫu nhiên
        for (let i = 0; i < 25; i++) {
            const heart = document.createElement('div');
            heart.className = 'intro-floating-heart';
            heart.innerText = heartIcons[Math.floor(Math.random() * heartIcons.length)];
            
            // Tọa độ ngang ngẫu nhiên
            heart.style.left = Math.random() * 100 + 'vw';
            
            // Kích thước ngẫu nhiên (từ 15px đến 35px)
            const size = 15 + Math.random() * 20;
            heart.style.fontSize = size + 'px';
            
            // Thời gian chạy và thời gian trễ ngẫu nhiên
            const duration = 5 + Math.random() * 4;
            const delay = Math.random() * 6;
            heart.style.animationDuration = duration + 's';
            heart.style.animationDelay = delay + 's';
            
            // Độ mờ ngẫu nhiên
            heart.style.opacity = 0.2 + Math.random() * 0.5;
            
            heartsContainer.appendChild(heart);
        }
    }
}

// 7. BỘ ĐẾM NGÀY YÊU NHAU (Love Counter)
/* =========================================================================
   CÁC HÀM TIỆN ÍCH HỆ THỐNG
   ========================================================================= */

// Sự kiện đổi kích thước cửa sổ trình duyệt
function onWindowResize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
}

// Xử lý sự kiện phóng to khi bấm vào 3 bức ảnh trái tim bay ở Cảnh 2
window.addEventListener('click', (event) => {
    // Chỉ xử lý khi đang ở Cảnh 2
    if (currentSceneIndex !== 1) return;
    
    // Sử dụng Raycaster của Three.js để phát hiện click trúng ảnh 3D
    const raycaster = new THREE.Raycaster();
    const mouse = new THREE.Vector2();
    
    mouse.x = (event.clientX / window.innerWidth) * 2 - 1;
    mouse.y = -(event.clientY / window.innerHeight) * 2 + 1;
    
    raycaster.setFromCamera(mouse, camera);
    const intersects = raycaster.intersectObjects(floatingGroup.children);
    
    if (intersects.length > 0) {
        const clickedObj = intersects[0].object;
        if (clickedObj.userData && clickedObj.userData.isPhoto) {
            openPhotoViewer(clickedObj.userData.url, clickedObj.userData.index);
        }
    }
});

// Trình xem ảnh kỷ niệm phóng to
const photoViewer = document.getElementById('photo-viewer');
const viewerImg = document.getElementById('viewer-img');
const viewerCaption = document.getElementById('viewer-caption');
const closeViewer = document.querySelector('.close-viewer');

function openPhotoViewer(url, index) {
    photoViewer.classList.add('active');
    viewerImg.src = url;
    viewerCaption.innerText = `Khoảnh khắc kỷ niệm ngọt ngào #${index + 1} 🥰`;
}

closeViewer.addEventListener('click', () => {
    photoViewer.classList.remove('active');
});

photoViewer.addEventListener('click', (e) => {
    if (e.target === photoViewer) {
        photoViewer.classList.remove('active');
    }
});

